import { useEffect, useRef, useState } from 'react';
import { TutorialBoard, type TileMark } from './TutorialBoard';
import './tutorial.css';

export const TUTORIAL_KEY = 'etch_seen_tutorial';

export function hasSeenTutorial(): boolean {
  try { return localStorage.getItem(TUTORIAL_KEY) === '1'; } catch { return false; }
}

export function markTutorialSeen(): void {
  try { localStorage.setItem(TUTORIAL_KEY, '1'); } catch { /* private mode etc. */ }
}

interface Step {
  title: string;
  body: string;
  rows: number[][];   // row clues
  cols: number[][];   // col clues
  marks: TileMark[];  // 5x5 row-major demo state
  highlight?: 'rowClue' | 'colClue' | 'fill' | 'cross';
}

/**
 * 5x5 demo puzzle: a small plus sign.
 *
 *    . . X . .
 *    . . X . .
 *    X X X X X
 *    . . X . .
 *    . . X . .
 *
 * Row clues: [1] [1] [5] [1] [1]
 * Col clues: [1] [1] [5] [1] [1]
 */
const PLUS_ROWS = [[1], [1], [5], [1], [1]];
const PLUS_COLS = [[1], [1], [5], [1], [1]];

// Final filled solution for the plus
const PLUS_SOLVED: TileMark[] = [
  'u', 'u', 'fill', 'u',    'u',
  'u', 'u', 'fill', 'u',    'u',
  'fill','fill','fill','fill','fill',
  'u', 'u', 'fill', 'u',    'u',
  'u', 'u', 'fill', 'u',    'u',
];

// Step 1 demo: highlight middle row's "5" clue, plus the row underlined
const STEP1_MARKS: TileMark[] = new Array(25).fill('u') as TileMark[];

// Step 2 demo: middle row partially filled
const STEP2_MARKS: TileMark[] = (() => {
  const m: TileMark[] = new Array(25).fill('u') as TileMark[];
  m[10] = 'fill'; m[11] = 'fill'; m[12] = 'fill'; m[13] = 'fill'; m[14] = 'fill';
  return m;
})();

// Step 3 demo: middle row filled, then row 0 has crosses except col 2
const STEP3_MARKS: TileMark[] = (() => {
  const m: TileMark[] = [...STEP2_MARKS];
  // Row 0 — only col 2 should be fill; the other 4 must be empty (cross)
  m[0] = 'cross'; m[1] = 'cross'; m[3] = 'cross'; m[4] = 'cross';
  return m;
})();

const STEPS: Step[] = [
  {
    title: 'Read the clue numbers',
    body: 'Numbers above a column and beside a row tell you the lengths of filled runs in that line, in order. The big "5" means: fill all 5 cells in that row.',
    rows: PLUS_ROWS,
    cols: PLUS_COLS,
    marks: STEP1_MARKS,
    highlight: 'rowClue',
  },
  {
    title: 'Tap / click to fill',
    body: 'Left-click (or tap on touch) fills a cell. The middle row was easy — its only clue "5" fills the whole row.',
    rows: PLUS_ROWS,
    cols: PLUS_COLS,
    marks: STEP2_MARKS,
    highlight: 'fill',
  },
  {
    title: 'Mark blanks with X',
    body: 'Right-click on desktop, or long-press on touch, marks a cell as definitely empty. Crossing-out blanks is how you solve harder puzzles — finish the plus to see.',
    rows: PLUS_ROWS,
    cols: PLUS_COLS,
    marks: STEP3_MARKS,
    highlight: 'cross',
  },
];

interface TutorialProps {
  onClose: () => void;
}

export function Tutorial({ onClose }: TutorialProps) {
  const [step, setStep] = useState(0);
  const dialogRef = useRef<HTMLDivElement>(null);
  const closeBtnRef = useRef<HTMLButtonElement>(null);

  // Mark seen the moment the tutorial is opened — we don't gate on "completed",
  // any view (even partial) counts. Re-open is via "?" any time.
  useEffect(() => { markTutorialSeen(); }, []);

  // Esc closes; focus the close button on open
  useEffect(() => {
    closeBtnRef.current?.focus();
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') { e.preventDefault(); onClose(); return; }
      if (e.key === 'ArrowRight') { e.preventDefault(); next(); return; }
      if (e.key === 'ArrowLeft') { e.preventDefault(); prev(); return; }
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
    // next/prev are stable enough; we read step from state inside them via setStep
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function next() { setStep(s => Math.min(STEPS.length - 1, s + 1)); }
  function prev() { setStep(s => Math.max(0, s - 1)); }
  function finish() { onClose(); }

  const s = STEPS[step]!;
  const isLast = step === STEPS.length - 1;

  return (
    <div
      className="etch-tutorial-backdrop"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
      role="presentation"
    >
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-label="How to play"
        aria-describedby="etch-tutorial-body"
        className="etch-tutorial-dialog"
      >
        <header className="etch-tutorial-header">
          <p className="etch-tutorial-eyebrow">How to play · {step + 1} of {STEPS.length}</p>
          <button
            ref={closeBtnRef}
            type="button"
            className="etch-tutorial-close"
            aria-label="Close tutorial"
            onClick={finish}
          >
            ×
          </button>
        </header>
        <h2 id="etch-tutorial-title" className="etch-tutorial-title">{s.title}</h2>
        <div className="etch-tutorial-demo">
          <TutorialBoard rows={s.rows} cols={s.cols} marks={s.marks} highlight={s.highlight} />
        </div>
        <p id="etch-tutorial-body" className="etch-tutorial-body">{s.body}</p>
        <footer className="etch-tutorial-footer">
          <div className="etch-tutorial-dots" aria-hidden="true">
            {STEPS.map((_, i) => (
              <span key={i} className="etch-tutorial-dot" data-active={i === step || undefined} />
            ))}
          </div>
          <div className="etch-tutorial-actions">
            {step > 0 && (
              <button type="button" className="etch-tutorial-btn-secondary" onClick={prev}>Back</button>
            )}
            {!isLast && (
              <button type="button" className="etch-tutorial-btn-secondary" onClick={finish}>Skip</button>
            )}
            {!isLast ? (
              <button type="button" className="etch-tutorial-btn-primary" onClick={next}>Next</button>
            ) : (
              <button type="button" className="etch-tutorial-btn-primary" onClick={finish}>Start playing</button>
            )}
          </div>
        </footer>
      </div>
    </div>
  );
}

// Re-export so tests can import directly from the same module if they want
export { PLUS_SOLVED };
